package com.example.banking.server;

import com.example.banking.BankingServiceEndpoint;
import com.example.banking.security.CxfWSSecurity;
import org.apache.cxf.Bus;
import org.apache.cxf.bus.extension.ExtensionManagerBus;
import org.apache.cxf.endpoint.Server;
import org.apache.cxf.frontend.ServerFactoryBean;
import org.apache.cxf.jaxws.JaxWsServerFactoryBean;
import org.apache.cxf.transport.servlet.CXFNonSpringServlet;
import org.eclipse.jetty.server.ServerConnector;
import org.eclipse.jetty.servlet.ServletContextHandler;
import org.eclipse.jetty.servlet.ServletHolder;

import java.util.Arrays;

public final class BankingCxfServer {

    public static void main(String[] args) throws Exception {
        int port = 8080;

        org.eclipse.jetty.server.Server jetty = new org.eclipse.jetty.server.Server();
        ServerConnector connector = new ServerConnector(jetty);
        connector.setPort(port);
        jetty.addConnector(connector);

        ServletContextHandler context = new ServletContextHandler(ServletContextHandler.SESSIONS);
        context.setContextPath("/");
        jetty.setHandler(context);

        CXFNonSpringServlet cxfServlet = new CXFNonSpringServlet();
        ServletHolder holder = new ServletHolder(cxfServlet);
        holder.setInitOrder(1);
        context.addServlet(holder, "/services/*");

        jetty.start();

        Bus bus = new ExtensionManagerBus();
        cxfServlet.setBus(bus);

        JaxWsServerFactoryBean factory = new JaxWsServerFactoryBean();
        factory.setBus(bus);
        factory.setServiceBean(new BankingServiceEndpoint());
        factory.setAddress("/BankingService");
        factory.getInInterceptors().add(CxfWSSecurity.inboundSignatureVerification("server-crypto.properties"));
        factory.getInInterceptors().add(new CxfWSSecurity.SignedElementsExtractorInterceptor());
        factory.getOutInterceptors().add(CxfWSSecurity.outboundSigning("server-crypto.properties", "serverkey", "changeit"));

        Server server = factory.create();
        System.out.println("CXF SOAP service published at http://localhost:" + port + "/services/BankingService?wsdl");

        jetty.join();
    }
}

