package com.example.banking.xmlsig;

import org.w3c.dom.*;
import javax.xml.crypto.dsig.*;
import javax.xml.crypto.dsig.dom.DOMValidateContext;
import javax.xml.crypto.*;
import javax.xml.parsers.DocumentBuilderFactory;
import java.io.InputStream;
import java.security.Key;
import java.security.KeyStore;
import java.security.PublicKey;
import java.security.cert.X509Certificate;
import java.util.*;

public final class SoapXmlSignatureVerifier {

    public static final class VerificationResult {
        public final boolean valid;
        public final List<String> signedReferenceUris;
        public final Map<String, Element> signedElementsById;

        public VerificationResult(boolean valid, List<String> signedReferenceUris, Map<String, Element> signedElementsById) {
            this.valid = valid;
            this.signedReferenceUris = signedReferenceUris;
            this.signedElementsById = signedElementsById;
        }
    }

    private SoapXmlSignatureVerifier() {}

    public static VerificationResult verify(InputStream soapXml, KeyStore trustStore, String trustAlias) throws Exception {
        DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
        dbf.setNamespaceAware(true);
        Document doc = dbf.newDocumentBuilder().parse(soapXml);
        doc.getDocumentElement().normalize();

        NodeList sigNodes = doc.getElementsByTagNameNS(XMLSignature.XMLNS, "Signature");
        if (sigNodes.getLength() == 0) throw new SecurityException("No XML Signature found");

        Element sigEl = (Element) sigNodes.item(0);

        PublicKey publicKey = resolvePublicKey(trustStore, trustAlias);
        DOMValidateContext valContext = new DOMValidateContext(publicKey, sigEl);
        setIdAttributes(doc, valContext);

        XMLSignatureFactory fac = XMLSignatureFactory.getInstance("DOM");
        XMLSignature signature = fac.unmarshalXMLSignature(valContext);

        boolean valid = signature.validate(valContext);

        List<String> uris = new ArrayList<>();
        Map<String, Element> elements = new LinkedHashMap<>();

        SignedInfo si = signature.getSignedInfo();
        for (Object o : si.getReferences()) {
            Reference r = (Reference) o;
            String uri = r.getURI();
            uris.add(uri);
            String id = uri != null && uri.startsWith("#") ? uri.substring(1) : uri;
            if (id != null && !id.isEmpty()) {
                Element el = findElementByAnyId(doc, id);
                if (el != null) elements.put(id, el);
            }
        }

        return new VerificationResult(valid, uris, elements);
    }

    private static PublicKey resolvePublicKey(KeyStore trustStore, String alias) throws Exception {
        if (alias != null) {
            X509Certificate cert = (X509Certificate) trustStore.getCertificate(alias);
            if (cert == null) throw new SecurityException("No certificate for alias: " + alias);
            return cert.getPublicKey();
        }
        Enumeration<String> aliases = trustStore.aliases();
        while (aliases.hasMoreElements()) {
            String a = aliases.nextElement();
            X509Certificate cert = (X509Certificate) trustStore.getCertificate(a);
            if (cert != null) return cert.getPublicKey();
        }
        throw new SecurityException("No certificate found in truststore");
    }

    private static void setIdAttributes(Document doc, DOMValidateContext ctx) {
        NodeList all = doc.getElementsByTagNameNS("*", "*");
        for (int i = 0; i < all.getLength(); i++) {
            Node n = all.item(i);
            if (n.getNodeType() != Node.ELEMENT_NODE) continue;
            Element e = (Element) n;

            if (e.hasAttributeNS("http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd", "Id")) {
                e.setIdAttributeNS("http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd", "Id", true);
            }
            if (e.hasAttribute("Id")) {
                e.setIdAttribute("Id", true);
            }
            if (e.hasAttributeNS("http://www.w3.org/XML/1998/namespace", "id")) {
                e.setIdAttributeNS("http://www.w3.org/XML/1998/namespace", "id", true);
            }
        }
    }

    private static Element findElementByAnyId(Document doc, String id) {
        Element byId = doc.getElementById(id);
        if (byId != null) return byId;

        NodeList all = doc.getElementsByTagNameNS("*", "*");
        for (int i = 0; i < all.getLength(); i++) {
            Node n = all.item(i);
            if (n.getNodeType() != Node.ELEMENT_NODE) continue;
            Element e = (Element) n;

            String wsuId = e.getAttributeNS("http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd", "Id");
            if (id.equals(wsuId)) return e;

            String plainId = e.getAttribute("Id");
            if (id.equals(plainId)) return e;

            String xmlId = e.getAttributeNS("http://www.w3.org/XML/1998/namespace", "id");
            if (id.equals(xmlId)) return e;
        }
        return null;
    }
}

